mapper.select:
SELECT fp.plan_id, fp.project_id, COALESCE(p.project_name, fp.project_name) AS project_name, fp.budget_amount, fp.plan_total, fp.arrived_total, fp.paid_total, fp.match_rate, CASE WHEN fp.budget_amount > 0 THEN ROUND((fp.arrived_total / fp.budget_amount) * 100, 2) ELSE 0 END AS arrived_rate, CASE WHEN fp.arrived_total > 0 THEN ROUND((fp.paid_total / fp.arrived_total) * 100, 2) ELSE 0 END AS paid_rate, fp.plan_status, fp.last_check_time, CASE WHEN fp.match_rate >= 90 THEN 'green' WHEN fp.match_rate >= 80 THEN 'yellow' ELSE 'red' END AS warning_level FROM invest_fund_plan fp LEFT JOIN invest_project p ON fp.project_id = p.project_id WHERE fp.del_flag = '0'
AND (p.project_name LIKE CONCAT('%', #{projectName}, '%') OR fp.project_name LIKE CONCAT('%', #{projectName}, '%'))
AND fp.plan_status = #{planStatus}
AND fp.match_rate >= #{matchRateLow}
AND fp.match_rate <= #{matchRateHigh}
ORDER BY fp.match_rate ASC
